  //De acuerdo a la categoría y subcategoría seleccionada, cargo los contornos que se van a dibujar (contorno 1)
  uploadBRContours(){
    let cargarContornos = [];
    let j = this.state.indexSubcategory;
    if(j>-1){
      if (this.state.percentil90 && this.state.percentil50) {
        while ((j < contorno_base.length) && (contorno_base[j][0] == this.state.titleDropDownBase) && (contorno_base[j][1] == this.state.titleSubDropDownBase)) {
          cargarContornos.push(contorno_base[j]);
          j++;
        }
      }
      else {
        if (this.state.percentil90 && !this.state.percentil50) {
          j = this.state.indexSubcategory;
          while ((j < contorno_base.length) && (contorno_base[j][0] === this.state.titleDropDownBase) &&
            (contorno_base[j][1] === this.state.titleSubDropDownBase)) {
              if ((parseInt(contorno_base[j][3]) === 90))
                cargarContornos.push(contorno_base[j]);
                j++;
             }
        }
        else {
          if (!this.state.percentil90 && this.state.percentil50) {
            j = this.state.indexSubcategory;
            while ((j < contorno_base.length) && (contorno_base[j][0] === this.state.titleDropDownBase) &&
               (contorno_base[j][1] === this.state.titleSubDropDownBase)) {
                 if ((parseInt(contorno_base[j][3]) === 50))
                    cargarContornos.push(contorno_base[j]);
                    j++;
            }
          }
        }
      }
   }
   this.loadBRContour(cargarContornos);
 }

