  /*
  * Carga contornos a renderizar (contorno 1)
  */
  loadBRContourAux(contour) {
    let contour1 = [];
    let contornos = [];
    let x = 0;
    let y = 0;
    let i = 5;

    if (contour.length > 0) {
      for (let k = 0; k < contour.length; k++) {

        let cantpoints = parseInt((contour[k][4]));
        i = 5;
        contour1 = [];

        for (let j = 0; j < cantpoints; j++) {
          x = parseFloat(contour[k][i]);
          y = parseFloat(contour[k][i + 1]);

          contour1.push([x / 100, y / 100]);
          i = i + 2;
        }
        contornos.push(contour1);
      }
    }
    this.setState({BRContours: contornos});
  }

