  /* Carga los labels de las categorias en el dropdown button*/
  loadCategories() {

     let aux = [];
     let auxCat = [];

     if (contorno_base.length > 0) {
       for (let i = 0; i < contorno_base.length; i++) {
         if (!(aux.includes(contorno_base[i][0]))) {
           aux.push(contorno_base[i][0]); //Arreglo auxiliar que lo uso para no repetir los nombres de categorias
           auxCat.push(<Dropdown.Item id={"CAT" + i} key={"CAT" + i} eventKey={"CAT" + i} className="menuitem-home"> {contorno_base[i][0]}</Dropdown.Item>);
         }
       }
       this.setState({categories: auxCat});
       this.setState({categories2: auxCat});
       this.setState({categories3: auxCat});
     }
  }

  /* Selecciona categoria del dropdownbutton y carga los labels de las subcategorias en el dropdown button (contorno 1)*/
  selectCategory(evt){
    let category = contorno_base[evt.toString().substr(3, 100)][0];
    this.setState({titleDropDownBase: category});

    this.setState({titleSubDropDownBase:"Subcategory"});//Al cambiar la category se borra la subcategory anteriormente seleccionada
    this.setState({indexSubcategory:-1});
    this.setState({BRContours:[]});
    this.setState({indexCategory: evt.toString().substr(3, 100)});

    let i = evt.toString().substr(3, 100);
    let aux = [];
    let auxSubcat = [];

    while (i < contorno_base.length && contorno_base[i][0] === category) {
        if (!(aux.includes(contorno_base[i][1]))) {
          aux.push(contorno_base[i][1]); //Arreglo auxiliar que lo uso para no repetir los nombres de categorys
          auxSubcat.push(<Dropdown.Item key={"SUB" + i} eventKey={"SUB" + i} className="menuitem-home"> {contorno_base[i][1]}</Dropdown.Item>);
        }
        i++;
    }
    this.setState({subcategories: auxSubcat});
  }

