   /*
   * Carga contornos a renderizar (contorno 1)
   */
    loadBRContourAux(contour) {
      let contour1 = [];
      let contornos = [];
      let a = 0;
      let b = 0;
      let c = 0;
      let i = 5;
      let point =  [];

      if (contour.length > 0) {
        for (let k = 0; k < contour.length; k++) {

          let cantpoints = parseInt((contour[k][4]));
          i = 5;
          contour1 = [];

          for (let j = 0; j < cantpoints; j++) {
            a = parseFloat(contour[k][i]);
            b = parseFloat(contour[k][i + 1]);
            c = parseFloat(contour[k][i + 2]);

            point = coord(a/100,b/100,c/100);
            contour1.push([point[0], point[1]]);
            i = i + 3;
          }
          contornos.push(contour1);
        }
      }
      this.setState({BRContours: contornos});
    }

